import ast
import operator

def evaluate_expression(expression: str):
    """
    Safely evaluate a mathematical expression string and return the numeric result.

    Supports: +, -, *, /, //, %, ** and parentheses, with numeric literals.
    Does NOT use eval() or exec() to avoid remote code execution (CWE-94).
    Instead, uses ast.parse to safely walk the expression tree.
    """
    # Only allow these operators
    ALLOWED_OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    ALLOWED_UNARY_OPERATORS = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval_node(node):
        # Numeric literal
        if isinstance(node, ast.Constant) and isinstance(node.value, (int, float, complex)):
            return node.value

        # Binary operation: e.g. 2 + 3
        if isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in ALLOWED_OPERATORS:
                raise ValueError(f"Unsupported binary operator: {op_type.__name__}")
            left = _eval_node(node.left)
            right = _eval_node(node.right)
            return ALLOWED_OPERATORS[op_type](left, right)

        # Unary operation: e.g. -5, +3
        if isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in ALLOWED_UNARY_OPERATORS:
                raise ValueError(f"Unsupported unary operator: {op_type.__name__}")
            operand = _eval_node(node.operand)
            return ALLOWED_UNARY_OPERATORS[op_type](operand)

        # Parenthesized expression (just an Expression wrapper)
        if isinstance(node, ast.Expression):
            return _eval_node(node.body)

        raise ValueError(f"Unsupported expression node: {type(node).__name__}")

    try:
        tree = ast.parse(expression.strip(), mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression: {expression!r}") from e

    return _eval_node(tree)


