import json


def evaluate_expression(expression: str) -> float:
    # Validate that the expression only contains safe mathematical characters
    allowed_chars = set("0123456789+-*/().% eE")
    if not all(c in allowed_chars for c in expression):
        raise ValueError(f"Expression contains disallowed characters: {expression}")

    # Additional safety: ensure no alphabetic sequences (no function calls, variable names, etc.)
    # Only allow 'e' or 'E' as part of scientific notation (e.g., 1e10)
    import re
    # Check for any letter sequences that aren't part of numeric scientific notation
    alpha_sequences = re.findall(r'[a-zA-Z]+', expression)
    for seq in alpha_sequences:
        if seq not in ('e', 'E'):
            raise ValueError(f"Expression contains disallowed identifier: {seq}")

    # Verify 'e'/'E' is only used in scientific notation context (digit before it)
    for match in re.finditer(r'[eE]', expression):
        pos = match.start()
        if pos == 0 or expression[pos - 1] not in '0123456789.':
            raise ValueError(f"'e'/'E' not used as scientific notation in: {expression}")

    # Use ast.literal_eval-style safety by compiling and checking the AST
    import ast
    try:
        tree = ast.parse(expression, mode='eval')
    except SyntaxError:
        raise ValueError(f"Invalid expression syntax: {expression}")

    # Walk the AST and only allow numeric literals and basic math operators
    allowed_node_types = (
        ast.Expression, ast.BinOp, ast.UnaryOp,
        ast.Num, ast.Constant,
        ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv,
        ast.Mod, ast.Pow, ast.USub, ast.UAdd,
    )
    for node in ast.walk(tree):
        if not isinstance(node, allowed_node_types):
            raise ValueError(f"Disallowed operation in expression: {type(node).__name__}")

    # Safe to evaluate since we've verified the AST only contains numeric literals and math ops
    code = compile(tree, "<expression>", "eval")
    result = eval(code, {"__builtins__": {}}, {})
    return float(result)

