import hashlib


def get_md5_hash(file_path: str) -> str:
    """Return the MD5 hex digest of a file's contents."""
    md5 = hashlib.md5()
    with open(file_path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            md5.update(chunk)
    return md5.hexdigest()

